import React, { useEffect, useRef } from 'react'
import { css } from '@linaria/core'
import { List, ExpandableListItem, ListItem } from '@fs/zion-ui'
import { trackLink } from '@fs/zion-analytics'
import { useTranslation } from 'react-i18next'
import debugLib from '@fs/zion-debug'
import { baseUrl } from '@fs/zion-config'
import { useNavigationContext } from '../shared/NavigationProvider'

// Determine if any section was opened due to currentApp; if no match, everything stays collapsed (default state)
const navContainerCss = css`
  min-width: 260px;
  display: flex;
  flex-direction: column;
  gap: 16px;
`

const slotsCss = css`
  display: flex;
  flex-direction: column;
  gap: 16px;
`

const debug = debugLib('header2019:nav')

export default function NavLinksMobile({ state, dispatch, external, currentApp, startSlot, endSlot }) {
  const [t] = useTranslation()

  const { headerNavigation } = useNavigationContext()
  debug('navigation Links:', headerNavigation)

  // Auto-expand current app section once (so user can still close or switch)
  const didInitRef = useRef(false)
  useEffect(() => {
    if (didInitRef.current || !headerNavigation?.length) return

    if (currentApp) {
      const target = headerNavigation.find((navigationItem) => navigationItem.id === currentApp)
      if (target?.sub?.length && !state[target.id]) {
        dispatch({ key: target.id, value: true })
      }
    }

    didInitRef.current = true
  }, [currentApp, headerNavigation, state, dispatch])

  const shouldShowSlots = Boolean(startSlot || endSlot)
  const StartSlot = startSlot
  const EndSlot = endSlot

  if (!headerNavigation) return null

  return (
    <nav aria-label={t('nav.main', 'Main')} className={navContainerCss}>
      <List>
        {headerNavigation.map((link) => (
          <ExpandableListItem
            primaryText={link.text}
            key={link.id}
            open={state[link.id]}
            setOpen={(value) => {
              const nextValue = typeof value === 'function' ? value(Boolean(state[link.id])) : value
              dispatch({ key: link.id, value: nextValue })
            }}
            data-test-id={`hdr_mobile_${link.id}`}
          >
            {link.sub.map((sub) => (
              <ListItem
                key={sub.text || sub.id}
                onClick={() =>
                  trackLink(null, sub.url, 'click_action', `hdr19_${link.id}:${sub.id}${sub.abTestString || ''}`)
                }
                to={`${external && sub.url.startsWith('/') ? baseUrl : ''}${sub.url}`}
                primaryText={sub.text}
                external
                dense
                data-test-id={`hdr_mobile_${link.id}_${sub.id}`}
              />
            ))}
          </ExpandableListItem>
        ))}
      </List>
      {shouldShowSlots && (
        <div className={slotsCss}>
          {StartSlot ? (
            <div data-mobile-slot="start">{typeof StartSlot === 'function' ? <StartSlot /> : StartSlot}</div>
          ) : null}
          {EndSlot ? <div data-mobile-slot="end">{typeof EndSlot === 'function' ? <EndSlot /> : EndSlot}</div> : null}
        </div>
      )}
    </nav>
  )
}
